import React from 'react';
import { Line, Pie, Radar, Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  Filler,
  ArcElement,
  RadialLinearScale
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
  Filler,
  ArcElement,
  RadialLinearScale
);

const DashboardView = ({ transactions = [] }) => {
  // --- Calculate Dynamic Stats ---
  const totalCount = transactions.length;
  const fraudCount = transactions.filter(t => t.status === 'flagged' || t.status === 'blocked').length;
  const blockedCount = transactions.filter(t => t.status === 'blocked').length;
  const approvedCount = transactions.filter(t => t.status === 'approved').length;

  const stats = [
    { label: 'TOTAL TRANSACTIONS', value: totalCount.toLocaleString(), delta: '+Live', icon: '📈', color: '#10b981' },
    { label: 'FRAUD DETECTED', value: fraudCount.toString(), delta: 'Detected', icon: '🛡️', color: '#ef4444' },
    { label: 'BLOCKED', value: blockedCount.toString(), delta: 'Stopped', icon: '🚫', color: '#3b82f6' }
  ];

  // --- Dynamic Pie Chart (Status Distribution) ---
  const pieData = {
    labels: ['Approved', 'Flagged', 'Blocked'],
    datasets: [{
      data: [approvedCount, fraudCount - blockedCount, blockedCount],
      backgroundColor: ['#10b981', '#f59e0b', '#ef4444'],
      borderWidth: 0
    }]
  };

  // --- Dynamic Bar Chart (Fraud by Merchant) ---
  const merchantFraud = {};
  transactions.filter(t => t.status !== 'approved').forEach(t => {
    merchantFraud[t.merchant] = (merchantFraud[t.merchant] || 0) + 1;
  });

  const barLabels = Object.keys(merchantFraud).slice(0, 5);
  const barValues = barLabels.map(label => merchantFraud[label]);

  const barData = {
    labels: barLabels.length > 0 ? barLabels : ['No Data'],
    datasets: [{
      label: 'Fraud Attempts',
      data: barValues.length > 0 ? barValues : [0],
      backgroundColor: '#f59e0b',
      borderRadius: 5
    }]
  };

  // --- Dynamic Line Chart (Volume by Time) ---
  const hourlyData = new Array(12).fill(0);
  const hours = ['00:00', '02:00', '04:00', '06:00', '08:00', '10:00', '12:00', '14:00', '16:00', '18:00', '20:00', '22:00'];

  transactions.forEach(t => {
    const hour = parseInt(t.time.split(':')[0]);
    const index = Math.floor(hour / 2);
    hourlyData[index]++;
  });

  const lineData = {
    labels: hours,
    datasets: [{
      label: 'Volume',
      data: hourlyData,
      borderColor: '#3b82f6',
      backgroundColor: 'rgba(59, 130, 246, 0.1)',
      fill: true,
      tension: 0.4
    }]
  };

  // --- Radar Chart (Risk Factors) ---
  // Using averages from live data for risk metrics
  const avgRisk = totalCount > 0 ? transactions.reduce((acc, t) => acc + (t.risk || 0), 0) / totalCount : 0;

  const radarData = {
    labels: ['Avg Risk', 'Max Risk', 'Fraud %', 'Blocked %', 'Alerts'],
    datasets: [{
      label: 'Live Risk Metrics',
      data: [
        avgRisk, 
        totalCount > 0 ? Math.max(...transactions.map(t => t.risk || 0)) : 0,
        totalCount > 0 ? (fraudCount / totalCount) * 100 : 0,
        totalCount > 0 ? (blockedCount / totalCount) * 100 : 0,
        fraudCount
      ],
      fill: true,
      backgroundColor: 'rgba(16, 185, 129, 0.2)',
      borderColor: '#10b981',
      pointBackgroundColor: '#10b981',
    }]
  };

  return (
    <div style={{ padding: '2rem' }}>
      <div style={{ marginBottom: '1.5rem' }}>
        <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '0.25rem' }}>Fraud Monitoring Dashboard</h2>
        <p style={{ color: '#94a3b8' }}>Real-time overview of transaction activity and threat detection</p>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem', marginBottom: '2rem' }}>
        {stats.map(stat => (
          <div key={stat.label} style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
              <p style={{ fontSize: '0.75rem', fontWeight: 'bold', color: '#94a3b8', letterSpacing: '0.05em' }}>{stat.label}</p>
              <span style={{ fontSize: '1.25rem' }}>{stat.icon}</span>
            </div>
            <h3 style={{ fontSize: '2rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>{stat.value}</h3>
            <p style={{ fontSize: '0.875rem', color: stat.color }}>{stat.delta}</p>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem', marginBottom: '1.5rem' }}>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>System Risk Radar</h3>
          <div style={{ height: '300px' }}>
             <Radar data={radarData} options={{ maintainAspectRatio: false, scales: { r: { grid: { color: '#334155' }, angleLines: { color: '#334155' }, pointLabels: { color: '#94a3b8' }, ticks: { display: false } } } }} />
          </div>
        </div>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Activity Volume (24h)</h3>
          <div style={{ height: '300px' }}>
            <Line data={lineData} options={{ maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#64748b' } }, y: { grid: { color: '#334155' }, ticks: { color: '#64748b' } } } }} />
          </div>
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Status Distribution</h3>
          <div style={{ height: '250px' }}>
            <Pie data={pieData} options={{ maintainAspectRatio: false, plugins: { legend: { position: 'right', labels: { color: '#94a3b8' } } } }} />
          </div>
        </div>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Top Fraud Merchants</h3>
          <div style={{ height: '250px' }}>
            <Bar data={barData} options={{ maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid: { display: false }, ticks: { color: '#64748b' } }, y: { grid: { color: '#334155' }, ticks: { color: '#64748b' } } } }} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;
